   799→          {/* Close Button */}
   800→          <div className="flex justify-end pt-2">
   801→            <button
   802→              onClick={() => setIsModalOpen(false)}
   803→              className="px-4 py-2 bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary rounded-lg hover:opacity-80 transition-opacity"
   804→            >
   805→              Close
   806→            </button>
   807→          </div>
   808→        </div>
   809→      </Modal>
   810→
   811→      {/* Recurring Event Dialog */}
   812→      <RecurringEventDialog
   813→        isOpen={isRecurringDialogOpen}
   814→        onClose={() => {
   815→          setIsRecurringDialogOpen(false);
   816→          setPendingRecurringEvent(null);
   817→        }}
   818→        onThisEvent={recurringAction === 'edit' ? handleEditThisEvent : handleDeleteThisEvent}
   819→        onAllEvents={recurringAction === 'edit' ? handleEditAllEvents : handleDeleteAllEvents}
   820→        action={recurringAction}
   821→        eventTitle={pendingRecurringEvent?.title || ''}
   822→      />
   823→    </Widget>
   824→  );
   825→};
   826→
   827→// ==================== MONTH VIEW COMPONENT ====================
   828→
   829→interface MonthViewProps {
   830→  currentDate: Date;
   831→  events: Record<string, CalendarEvent[]>;
   832→  tasks: Task[];
   833→  onDayClick: (dateKey: string) => void;
   834→}
   835→
   836→const MonthView: React.FC<MonthViewProps> = ({
   837→  currentDate,
   838→  events,
   839→  tasks,
   840→  onDayClick,
   841→}) => {
   842→  const year = currentDate.getFullYear();
   843→  const month = currentDate.getMonth();
   844→
   845→  const firstDay = getFirstDayOfMonth(currentDate);
   846→  const daysInMonth = getDaysInMonth(currentDate);
   847→  const daysInPrevMonth = getDaysInPrevMonth(currentDate);
   848→
   849→  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
   850→
   851→  // Generate day cells
   852→  const dayCells = useMemo(() => {
   853→    const cells = [];
   854→
   855→    // Previous month days
   856→    for (let i = firstDay - 1; i >= 0; i--) {
   857→      const dayNum = daysInPrevMonth - i;
   858→      const date = new Date(year, month - 1, dayNum);
   859→      cells.push({
   860→        date,
   861→        dayNum,
   862→        isOtherMonth: true,
   863→        isToday: false,
   864→        dateKey: getLegacyDateKey(date),
   865→      });
   866→    }
   867→
   868→    // Current month days
   869→    for (let i = 1; i <= daysInMonth; i++) {
   870→      const date = new Date(year, month, i);
   871→      const dateKey = getLegacyDateKey(date);
   872→      cells.push({
   873→        date,
   874→        dayNum: i,
   875→        isOtherMonth: false,
   876→        isToday: isToday(date),
   877→        dateKey,
   878→      });
   879→    }
   880→
   881→    // Next month days (to fill grid)
   882→    const totalCells = cells.length;
   883→    const remainingCells = 35 - totalCells;
   884→    for (let i = 1; i <= remainingCells; i++) {
   885→      const date = new Date(year, month + 1, i);
   886→      cells.push({
   887→        date,
   888→        dayNum: i,
   889→        isOtherMonth: true,
   890→        isToday: false,
   891→        dateKey: getLegacyDateKey(date),
   892→      });
   893→    }
   894→
   895→    return cells;
   896→  }, [year, month, firstDay, daysInMonth, daysInPrevMonth]);
   897→
   898→  // Filter tasks with date ranges (memoized to avoid re-filtering on every render)
   899→  const tasksWithDates = useMemo(
   900→    () => tasks.filter((task) => task.startDate && task.dueDate),
   901→    [tasks]
   902→  );
   903→
   904→  return (
   905→    <div className="calendar-month-view flex-1 grid grid-rows-[auto_1fr] gap-2">
   906→      {/* Day headers */}
   907→      <div className="grid grid-cols-7 gap-px">
   908→        {days.map((day) => (
   909→          <div
   910→            key={day}
   911→            className="calendar-day-header text-center font-semibold text-sm text-text-light-secondary dark:text-text-dark-secondary py-2"
   912→          >
   913→            {day}
   914→          </div>
   915→        ))}
   916→      </div>
   917→
   918→      {/* Day cells */}
   919→      <div className="grid grid-cols-7 grid-rows-5 gap-px">
   920→        {dayCells.map((cell, index) => {
   921→          const hasEvent = (events[cell.dateKey]?.length || 0) > 0;
   922→
   923→          return (
   924→            <DayCell
   925→              key={index}
   926→              date={cell.date}
   927→              dayNum={cell.dayNum}
   928→              isOtherMonth={cell.isOtherMonth}
   929→              isToday={cell.isToday}
   930→              hasEvent={hasEvent}
   931→              dateKey={cell.dateKey}
   932→              tasks={tasksWithDates}
   933→              events={events}
   934→              onClick={() => !cell.isOtherMonth && onDayClick(cell.dateKey)}
   935→            />
   936→          );
   937→        })}
   938→      </div>
   939→    </div>
   940→  );
   941→};
   942→
   943→// ==================== DAY CELL COMPONENT ====================
   944→
   945→interface DayCellProps {
   946→  date: Date;
   947→  dayNum: number;
   948→  isOtherMonth: boolean;
   949→  isToday: boolean;
   950→  hasEvent: boolean;
   951→  dateKey: string;
   952→  tasks: Task[];
   953→  events: Record<string, CalendarEvent[]>;
   954→  onClick: () => void;
   955→}
   956→
   957→const DayCellComponent: React.FC<DayCellProps> = ({
   958→  date,
   959→  dayNum,
   960→  isOtherMonth,
   961→  isToday,
   962→  hasEvent,
   963→  dateKey,
   964→  tasks,
   965→  events,
   966→  onClick,
   967→}) => {
   968→  // Find tasks that overlap this day
   969→  const overlappingTasks = tasks.filter((task) => {
   970→    const startDate = new Date(task.startDate!);
   971→    const dueDate = new Date(task.dueDate!);
   972→    return isDateBetween(date, startDate, dueDate);
   973→  });
   974→
   975→  const priorityColors = {
   976→    low: 'bg-accent-cyan',
   977→    medium: 'bg-status-warning',
   978→    high: 'bg-status-error',
   979→  };
   980→
   981→  return (
   982→    <div
   983→      onClick={onClick}
   984→      className={`
   985→        calendar-day
   986→        relative
   987→        border rounded
   988→        p-2
   989→        min-h-[100px]
   990→        cursor-pointer
   991→        transition-all
   992→        hover:shadow-md
   993→        ${isOtherMonth ? 'bg-neutral-100 dark:bg-neutral-700 opacity-50' : 'bg-surface-light-elevated dark:bg-neutral-800'}
   994→        ${isToday ? 'ring-2 ring-accent-cyan' : 'border-neutral-200 dark:border-neutral-700'}
   995→        ${hasEvent ? 'border-accent-magenta' : ''}
   996→      `}
   997→    >
   998→      {/* Day number */}
   999→      <div
  1000→        className={`
  1001→          calendar-day-number
  1002→          text-sm font-semibold
  1003→          ${isToday ? 'text-accent-cyan' : 'text-text-light-secondary dark:text-text-dark-secondary'}
  1004→        `}
  1005→      >
  1006→        {dayNum}
  1007→      </div>
  1008→
  1009→      {/* Event indicator dot */}
  1010→      {hasEvent && (
  1011→        <div className="absolute top-1 right-1 w-2 h-2 bg-accent-magenta rounded-full"></div>
  1012→      )}
  1013→
  1014→      {/* Event text (if no tasks to show room for) */}
  1015→      {hasEvent && overlappingTasks.length === 0 && (
  1016→        <div className="mt-1 space-y-1">
  1017→          {events[dateKey].slice(0, 2).map((event) => {
  1018→            const showLeftArrow = event._isMultiDayPart && !event._isMultiDayFirst;
  1019→            const showRightArrow = event._isMultiDayPart && !event._isMultiDayLast;
  1020→            return (
  1021→              <div
  1022→                key={event.id}
  1023→                className="text-xs text-accent-magenta font-medium truncate px-1 flex items-center gap-0.5"
  1024→              >
  1025→                {showLeftArrow && <span className="text-accent-magenta">←</span>}
  1026→                <span className="flex-1 truncate">{event.title}</span>
  1027→                {showRightArrow && <span className="text-accent-magenta">→</span>}
  1028→              </div>
  1029→            );
  1030→          })}
  1031→          {events[dateKey].length > 2 && (
  1032→            <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary px-1">
  1033→              +{events[dateKey].length - 2} more
  1034→            </div>
  1035→          )}
  1036→        </div>
  1037→      )}
  1038→
  1039→      {/* Task bars */}
  1040→      <div className="mt-1 space-y-1">
  1041→        {overlappingTasks.slice(0, 2).map((task) => (
  1042→          <div
  1043→            key={task.id}
  1044→            className={`
  1045→              calendar-task-bar
  1046→              text-xs
  1047→              px-1
  1048→              py-0.5
  1049→              rounded
  1050→              text-white
  1051→              truncate
  1052→              ${priorityColors[task.priority || 'medium']}
  1053→            `}
  1054→            title={task.title}
  1055→          >
  1056→            {task.title}
  1057→          </div>
  1058→        ))}
  1059→        {overlappingTasks.length > 2 && (
  1060→          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
  1061→            +{overlappingTasks.length - 2} more
  1062→          </div>
  1063→        )}
  1064→      </div>
  1065→    </div>
  1066→  );
  1067→};
  1068→
  1069→// Memoize DayCell to prevent unnecessary re-renders (35 cells per month view)
  1070→const DayCell = React.memo(DayCellComponent, (prevProps, nextProps) => {
  1071→  return (
  1072→    prevProps.dayNum === nextProps.dayNum &&
  1073→    prevProps.isOtherMonth === nextProps.isOtherMonth &&
  1074→    prevProps.isToday === nextProps.isToday &&
  1075→    prevProps.hasEvent === nextProps.hasEvent &&
  1076→    prevProps.dateKey === nextProps.dateKey &&
  1077→    prevProps.tasks.length === nextProps.tasks.length
  1078→  );
  1079→});
